const vars = $('Configuration').first().json || {};
const rawData = $input.first().json;
const companies = rawData.data || []; 
const prompt = `Evaluate these companies based on criteria: ${vars.company_filter_prompt}\n\nCompanies:\n${companies.map(c => `ID: ${c.companyId || c.id} | Name: ${c.name}`).join('\n')}\n\nReturn JSON array of {id, is_relevant, reasoning}`;

const payload = {
  contents: [
    {
      parts: [
        {
          text: prompt
        }
      ]
    }
  ],
  generationConfig: { "response_mime_type": "application/json", "temperature": vars.ai_temperature || 0.1 }
};
return { json: { ...rawData, gemini_payload: payload, original_prompt: prompt, retry_count: 0 } };

const input = $input.first().json;
const response = input.candidates?.[0]?.content?.parts?.[0]?.text;

try {
  if (!response) throw new Error("Empty response from AI");
  const results = JSON.parse(response);
  const rawCompanies = $('Lusha: Search Companies').first().json.data || [];
  const relevantCompanies = rawCompanies.filter(c => results.find(r => String(r.id) === String(c.companyId || c.id) && r.is_relevant));
  return { json: { success: true, relevant_companies: relevantCompanies, results: results, retry_count: input.retry_count } };
} catch (e) {
  return { json: { success: false, error: e.message, raw_response: response, original_prompt: input.original_prompt, retry_count: input.retry_count } };
}

