const vars = $('Configuration').first().json;

return $input.all().map(item => {
  const contacts = item.json.data || [];
  const companyName = contacts[0]?.companyName || "Unknown Company";

  const prompt = `Select top ${vars.target_contact_count} contacts for ${companyName} based on: ${vars.contact_filter_prompt}\n\nContacts:\n${contacts.map(c => `${c.contactId}: ${c.name} (${c.jobTitle})`).join('\n')}`;

  const payload = {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { "response_mime_type": "application/json", "temperature": vars.ai_temperature || 0.1 }
  };

  return { 
    json: { 
      ...item.json, 
      gemini_payload: payload, 
      original_prompt: prompt, 
      retry_count: 0 
    } 
  };
});

const items = $input.all();
const successes = items.filter(i => !i.json.error);
const failures = items.filter(i => i.json.error);

let text = (failures.length === 0) ? "✅ *Pipeline Successful*" : "⚠️ *Pipeline Finished with Errors*";
text += `\n\n📊 Leads Processed: ${items.length}`;
text += `\n✅ Successes: ${successes.length}`;

if (failures.length > 0) {
  text += `\n❌ Failures: ${failures.length}`;
  text += "\n\n*Recent Errors:*\n";
  failures.slice(0, 5).forEach(f => {
    const errMsg = f.json.error?.message || "Unknown error";
    text += `- ${errMsg.substring(0, 100)}\n`;
  });
}

text += `\n⏱ ${new Date().toLocaleString()}`;

return [{
  json: {
    chat_id: $('Configuration').first().json.telegram_chat_id,
    text: text,
    parse_mode: "Markdown"
  }
}];

const input = $input.first().json;
if (input.retry_count >= 1) {
  throw new Error(`AI Filter failed after retry. Error: ${input.error}`);
}
const newPrompt = `The previous response was invalid or caused an error: ${input.error}\n\nRaw response received: ${input.raw_response}\n\nPlease fix the response and ensure it follows the required JSON format.\n\nOriginal Request:\n${input.original_prompt}`;
const payload = {
  contents: [{ parts: [{ text: newPrompt }] }],
  generationConfig: { "response_mime_type": "application/json", "temperature": $('Configuration').first().json.ai_temperature || 0.1 }
};
return { json: { ...input, gemini_payload: payload, retry_count: input.retry_count + 1 } };

const input = $input.first().json;
const error = input._originalInput; 
return [{
  json: {
    chat_id: $('Configuration').first().json.telegram_chat_id,
    text: `❌ *Pipeline Failure*\n\n⚠️ Error: ${error.execution.error.message}\n📍 Node: ${error.execution.lastNodeName}`,
    parse_mode: "MarkdownV2"
  }
}];

const lushaItems = $('Lusha: Get People').all();

return $input.all().flatMap((item, index) => {
  const input = item.json;
  const response = input.candidates?.[0]?.content?.parts?.[0]?.text;

  try {
    if (!response) throw new Error("Empty response from AI");
    const result = JSON.parse(response);

    let contactsToProcess = [];
    if (Array.isArray(result)) {
      contactsToProcess = result;
    } else {
      contactsToProcess = result.selected_contacts || result.contacts || result.data || [];
    }

    if (contactsToProcess.length === 0) {
      throw new Error("AI returned zero contacts or invalid format");
    }

    const originalData = lushaItems[index]?.json?.data || [];

    const selected = contactsToProcess.map(s => {
      const contactId = s.id || s.contactId;
      const full = originalData.find(o => String(o.contactId) === String(contactId));
      return full ? { ...s, ...full } : null;
    }).filter(c => c !== null);

    if (selected.length === 0) {
      throw new Error("Could not match AI response with any original contacts");
    }

    return selected.map(s => ({ 
      json: { ...s, success: true, retry_count: input.retry_count } 
    }));

  } catch (e) {
    return [{ 
      json: { 
        success: false, 
        error: e.message, 
        raw_response: response, 
        original_prompt: input.original_prompt, 
        retry_count: input.retry_count 
      } 
    }];
  }
});

return $input.all().map(item => {
  const input = item.json;

  if (input.retry_count >= 1) {
    throw new Error(`AI Filter failed after retry. Error: ${input.error}`);
  }

  const newPrompt = `The previous response was invalid or caused an error: ${input.error}\n\nRaw response received: ${input.raw_response}\n\nPlease fix the response and ensure it follows the required JSON format.\n\nOriginal Request:\n${input.original_prompt}`;

  const payload = {
    contents: [{ parts: [{ text: newPrompt }] }],
    generationConfig: { "response_mime_type": "application/json", "temperature": $('Configuration').first().json.ai_temperature || 0.1 }
  };

  return { 
    json: { 
      ...input, 
      gemini_payload: payload, 
      retry_count: input.retry_count + 1 
    } 
  };
});

