  (() => {
    const enrichedData = $('Lusha: Enrichment').item.json.contact?.data || {};
    const fallbackData = $json; 
    const props = {};

    let firstName = enrichedData.firstName || '';
    let lastName = enrichedData.lastName || '';

    if (!firstName && fallbackData.name) {
      const nameParts = fallbackData.name.split(' ');
      firstName = nameParts[0];
      lastName = nameParts.slice(1).join(' ');
    }

    if (firstName) props.firstname = firstName;
    if (lastName) props.lastname = lastName;

    const email = enrichedData.emailAddresses?.[0]?.email;
    if (email) props.email = email;

    const job = enrichedData.jobTitle?.title || enrichedData.jobTitle || fallbackData.jobTitle;
    if (job) props.jobtitle = job;

    const company = enrichedData.company?.name || enrichedData.companyName || fallbackData.companyName;
    if (company) props.company = company;

    return { "properties": props };
  })()
}}

