const fs = require('fs');

// Default values
const defaults = {
  "Industries": "Real Estate",
  "Locations (Countries)": "United Kingdom",
  "City": "London",
  "Company Limit": 10,
  "People Per Company Limit": 10,
  "company_filter_prompt": "Identify companies relevant to residential real estate development and investment. Exclude general consulting if they don't develop properties.",
  "contact_filter_prompt": "Identify decision-makers in IT, Operations, or Strategy. Focus on Directors and C-level.",
  "target_contact_count": 2,
  "gemini_model": "gemini-2.5-flash",
  "ai_temperature": 0.1,
  "job_titles": "Director, Manager, Owner",
  "spreadsheet_id": "1S4c_u89MmNbY5adar_QhBBds1Bb-8o6yrzIvswjCEj0",
  "hubspot_user_id": "29480403",
  "hubspot_sequence_id": "806741197",
  "telegram_chat_id": "1322565480",
  "Delay: Lusha Search (s)": 1,
  "Delay: Gemini (s)": 2,
  "Delay: Lusha Enrichment (s)": 3,
  "Delay: HubSpot (s)": 2,
  "sender_email": "anastasian@rocketscience.lv"
};

const items = $input.all();
const item = items[0] || { json: {} };

// Handle both Form Trigger (direct json) and Webhook (body)
const inputData = item.json.body || item.json || {};
const json = { ...defaults, ...inputData };

// Mapping form names to logical names if they differ
if (json['Gemini Model']) json.gemini_model = json['Gemini Model'];
if (json['AI Temperature']) json.ai_temperature = json['AI Temperature'];
if (json['Job Titles']) json.job_titles = json['Job Titles'];

// Convert number-like strings to numbers
['Company Limit', 'People Per Company Limit', 'target_contact_count', 'ai_temperature', 'Delay: Lusha Search (s)', 'Delay: Gemini (s)', 'Delay: Lusha Enrichment (s)', 'Delay: HubSpot (s)'].forEach(key => {
  if (json[key] !== undefined && typeof json[key] === 'string') {
    const val = parseFloat(json[key]);
    if (!isNaN(val)) json[key] = val;
  }
});

// Sync secondary logical names if they were converted
if (json.ai_temperature) json['AI Temperature'] = json.ai_temperature;

const countryMap = {
  "United Kingdom": "GB",
  "United States": "US",
  "Germany": "DE",
  "France": "FR",
  "Spain": "ES",
  "Italy": "IT",
  "Canada": "CA",
  "Australia": "AU",
  "Netherlands": "NL"
};

if (json['Locations (Countries)']) {
  json['CountryCode'] = countryMap[json['Locations (Countries)']] || json['Locations (Countries)'];
}

// Determine trigger source
let triggerType = 'unknown';
if (item.json.body) triggerType = 'webhook';
else if (item.json.path && item.json.formTitle) triggerType = 'form';
else if (item.json.execution) triggerType = 'error';
else triggerType = 'cron';

let envContent = '';
if (item.binary) {
  const envFileKey = Object.keys(item.binary).find(key => key.toLowerCase().includes('env'));
  if (envFileKey && item.binary[envFileKey]) {
    envContent = Buffer.from(item.binary[envFileKey].data, 'base64').toString('utf8');
  }
}

if (!envContent) {
  try {
    if (fs.existsSync('/files/.env')) {
      envContent = fs.readFileSync('/files/.env', 'utf8');
    }
  } catch (e) {}
}

if (envContent) {
  const lines = envContent.split(/\r?\n/);
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed && !trimmed.startsWith('#')) {
      const separatorIndex = trimmed.indexOf('=');
      if (separatorIndex > 0) {
        const key = trimmed.substring(0, separatorIndex).trim();
        const value = trimmed.substring(separatorIndex + 1).trim().replace(/^[\"\']|[\"\']$/g, '');
        json[key] = value;
      }
    }
  }
}

// FIXED: Prioritize explicitly set form value first, but allow .env to override defaults
if (json['HubSpot Sender Email']) {
  json['sender_email'] = json['HubSpot Sender Email'];
}
if (json['HUBSPOT_EMAIL']) {
  json['sender_email'] = json['HUBSPOT_EMAIL'];
}

// Keep original input for error reporting if applicable
return [{ json: { ...json, _triggerType: triggerType, _originalInput: item.json } }];
